TranslateName": "专业精深创新企业"}, {"labelCode": "gov_owned_supplier", "labelDefinition": "经芝麻通过公开数据识别，该企业过去1年曾中标国企单位的招标项目。属于云南红塔银行股份有限公司供应商，其具有较高的资金实力和经营能力。", "labelName": "国企供应商"}, {"labelCode": "innovative_sme", "labelDefinition": "发布时间:2024-11-14,评定有效期:3年,颁发机构:广东省工业和信息化厅。企业符合《优质中小企业梯度培育管理暂行办法》中创新型中小企业的认定条件，说明企业在技术、管理、市场和组织等方面具备较强的创新能力和发展潜力。", "labelName": "创新型中小企业", "labelTranslateName": "创新成长型中小企业"}, {"labelCode": "province_tech_center", "labelDefinition": "发布时间:2023-10-26,评定有效期:3年,颁发机构:广东省工业和信息化厅。符合《国家企业技术中心认定管理办法》规定，企业根据市场竞争需要设立的技术研发与创新机构，负责制定企业技术创新规划、开展产业技术研发、创造运用知识产权、建立技术标准体系、凝聚培养创新人才、构建协同创新网络、推进技术创新全过程实施。", "labelName": "省级企业技术中心"}, {"labelCode": "state_owned_business", "labelDefinition": "该企业为实际控制人为国务院、各地区国有资产监督管理委员会、地方人民政府或机关单位。", "labelName": "国有企业"}, {"labelCode": "stock_market_child", "labelDefinition": "经芝麻通过公开数据识别，企业为广电运通子公司。", "labelName": "上市企业子公司"}, {"labelCode": "high_new_tech_corp", "labelDefinition": "发布时间:2024-11-28,评定有效期:3年,颁发机构:全国高新技术企业认定管理工作领导小组办公室。符合《高新技术企业认定管理办法》规定，符合国家重点支持的高新技术领域，持续进行研究开发与技术成果转化，形成企业核心自主知识产权，并以此为基础开展经营活动，在中国境内（不包括港、澳、台地区）注册成立一年以上的居民企业。", "labelName": "高新技术企业", "labelTranslateName": "技术创新卓越企业"}, {"labelCode": "province_engineering_reserch_center", "labelDefinition": "发布时间:2020-12-21,颁发机构:广东省科学技术厅。符合《工程技术研究中心管理办法》的要求，企业、科研院所、高校或其他具有科技创新能力的机构建设的科研实体，拥有高水平的工程技术研发队伍，具有较完备的工程化综合配套条件，较强的技术创新能力、成果转化能力和行业服务能力，并与国内相关企业联系紧密，对本行业发展有引领作用。", "labelName": "省级工程技术研究中心"}, {"labelCode": "top_nationwide", "labelDefinition": "据工商登记信息显示，该企业相比其他同行业更早进入市场。", "labelName": "经营年限全国同行前10%", "labelTranslateName": "经营年限全国同行前10%"}, {"labelCode": "new_strategic_industry", "labelDefinition": "该企业申请、授权的专利属于以重大技术突破和重大发展需求为基础，对经济社会全局和长远发展具有重大引领带动作用，知识技术密集、物质资源消耗少、成长潜力大、综合效益好的战略性新兴产业。", "labelName": "战略性新兴领域创新能力", "labelTranslateName": "新兴领域创新企业"}, {"labelCode": "has_patent_high", "labelDefinition": "该企业拥有一项或多项高价值专利。高价值专利是指为专利权人带来高额收益或者竞争优势的专利。", "labelName": "拥有高价值专利"}, {"labelCode": "pat_grant_top_num", "labelDefinition": "据企业官方和专利局网站信息显示，该企业在核算装置领域获得的专利授权数量在同行业位于前列。", "labelName": "专利授权量同领域前500"}, {"labelCode": "tech_layout_leader", "labelDefinition": "该企业所采用的技术或技术路线已经或正在成为该行业的主流趋势，相比同行业具有较高的市场竞争力和创新能力。", "labelName": "技术布局行业领先"}, {"labelCode": "ability_innovation", "labelDefinition": "根据企业公开的和国家专利局网站公示的专利信息显示，本企业拥有突出的工艺创新能力，在生产过程中，通过设计和实施新的生产工艺或改进现有工艺，实现生产效率和产品质量的提高，也降低了生产成本；同时也表明了本企业在技术水平、技术人才、创新发展等方面拥有较强的企业实力。", "labelName": "拥有工艺创新能力", "labelTranslateName": "工艺/技术创新能力突出"}, {"labelCode": "esg_certificate_e", "labelDefinition": "该企业拥有环保绿色相关资质认证。", "labelName": "拥有绿色资质", "labelTranslateName": "拥有绿色资质"}, {"labelCode": "own_independent_brand", "labelDefinition": "该企业拥有中智融通自主品牌。", "labelName": "拥有自主品牌"}], "showTypeUrl": "https://imgjl.51jobcdn.com/cdn/51job/FileService/FileUpload/image/20250520/ptcard_128e85b893a640e8940c74c70daada54.png", "showTypeUrlDark": "https://imgjl.51jobcdn.com/cdn/51job/FileService/FileUpload/image/20251208/a7401c7dc5b291eef900ff6b78327e18_f2a16bd811034ae78dea2e01b9945aee.png", "smallHrLogoUrl": "", "term": "0", "termStr": "全职", "triggerBatchDeliver": true, "updateDateTime": "2026-04-09 10:56:57", "userInteractionOnlineLabel": 2, "workAreaCode": "310201", "workYear": "3", "workYearString": "1年及以上"}

